import type { Topic } from "./arcadeQuestions";

// ══════════════════════════════════════════════════
// HTML/CSS — OUTPUT GUESS (💻)
// ══════════════════════════════════════════════════
export const HTMLCSS_OUTPUT_TOPICS: Topic[] = [
  { id:"htmlcss-out-selectors", name:"Output: CSS Selectors", icon:"💻", difficulty:"Easy", category:"CSS", questions:[
    {id:1,question:"What color will the paragraph be?\n\n<style>\n  p { color: blue; }\n  .text { color: red; }\n</style>\n<p class='text'>Hello</p>",options:["blue","red","black","Error"],answer:"red",explanation:"Class selector (.text) has higher specificity (0,1,0) than element selector p (0,0,1). Red wins."},
    {id:2,question:"What color will the div be?\n\n<style>\n  #box { color: green; }\n  .box { color: red; }\n  div { color: blue; }\n</style>\n<div id='box' class='box'>Hi</div>",options:["blue","red","green","black"],answer:"green",explanation:"ID selector (#box) has highest specificity (1,0,0) > class (0,1,0) > element (0,0,1). Green wins."},
    {id:3,question:"What is the computed width?\n\n<style>\n  .box {\n    width: 200px;\n    padding: 20px;\n    box-sizing: content-box;\n  }\n</style>",options:["200px","240px","180px","160px"],answer:"240px",explanation:"content-box: total width = width + padding. 200 + 20 + 20 = 240px total rendered width."},
    {id:4,question:"What is the computed width?\n\n<style>\n  .box {\n    width: 200px;\n    padding: 20px;\n    box-sizing: border-box;\n  }\n</style>",options:["200px","240px","160px","180px"],answer:"200px",explanation:"border-box: padding included in width. Total = 200px. Content area = 200 - 20 - 20 = 160px inside."},
    {id:5,question:"Which element gets the style?\n\n<style>\n  div > p { color: red; }\n</style>\n<div>\n  <p>Direct child</p>\n  <span><p>Nested</p></span>\n</div>",options:["Both paragraphs","Only 'Direct child'","Only 'Nested'","Neither"],answer:"Only 'Direct child'",explanation:"Child combinator (>) selects direct children only. 'Direct child' p is direct child of div. 'Nested' p is grandchild."},
    {id:6,question:"What specificity does this selector have?\n\na.active:hover",options:["(0,1,1)","(0,2,1)","(0,1,2)","(1,1,1)"],answer:"(0,2,1)",explanation:"a = element (1), .active = class (10), :hover = pseudo-class (10). Total = (0, 2, 1)."},
    {id:7,question:"What does this CSS output?\n\n<style>\n  p::before {\n    content: '>> ';\n  }\n</style>\n<p>Hello</p>",options:["Hello",">> Hello","Hello >>",">>Hello"],answer:">> Hello",explanation:"::before inserts content before element's content. Content '>> ' + 'Hello' = '>> Hello'."},
    {id:8,question:"Which elements get styled?\n\n<style>\n  li + li { color: red; }\n</style>\n<ul>\n  <li>One</li>\n  <li>Two</li>\n  <li>Three</li>\n</ul>",options:["All li","Only One","Two and Three","Only Two"],answer:"Two and Three",explanation:"Adjacent sibling combinator (+) selects element immediately after another. Two and Three each follow a li."},
    {id:9,question:"What is the output?\n\n<style>\n  .parent { font-size: 20px; }\n  .child { font-size: 1.5em; }\n</style>\n<div class='parent'>\n  <div class='child'>Text</div>\n</div>",options:["20px","30px","1.5px","15px"],answer:"30px",explanation:"em is relative to parent font-size. .child: 1.5em × 20px = 30px."},
    {id:10,question:"What is the result?\n\n<style>\n  :root { --color: blue; }\n  p { color: var(--color); }\n</style>\n<p>Hello</p>",options:["black","Error","blue","var(--color)"],answer:"blue",explanation:"CSS custom property --color defined as blue. var(--color) references it. p gets color: blue."},
  ]},
  { id:"htmlcss-out-layout", name:"Output: Flexbox & Grid", icon:"💻", difficulty:"Medium", category:"CSS", questions:[
    {id:1,question:"How many columns in this grid?\n\n<style>\n  .grid {\n    display: grid;\n    grid-template-columns: 100px 200px 100px;\n  }\n</style>",options:["1","2","3","4"],answer:"3",explanation:"grid-template-columns defines 3 values = 3 columns: 100px, 200px, 100px."},
    {id:2,question:"What direction do flex items go by default?\n\n<style>\n  .flex { display: flex; }\n</style>",options:["column","row-reverse","column-reverse","row"],answer:"row",explanation:"flex-direction default is row — items laid out horizontally left to right."},
    {id:3,question:"Where does the item end up?\n\n<style>\n  .container {\n    display: flex;\n    justify-content: flex-end;\n  }\n</style>",options:["Left","Center","Right (end of main axis)","Top"],answer:"Right (end of main axis)",explanation:"justify-content: flex-end pushes items to end of main axis. Default flex-direction: row, so items go to the right."},
    {id:4,question:"What width does each item get?\n\n<style>\n  .container { display: flex; width: 300px; }\n  .item { flex: 1; }\n</style>\n<!-- 3 items inside -->",options:["300px","150px","100px","auto"],answer:"100px",explanation:"flex: 1 distributes space equally. 300px / 3 items = 100px each."},
    {id:5,question:"What does this produce?\n\n<style>\n  .grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 10px;\n  }\n</style>\n<!-- 6 items -->",options:["1 row 6 cols","2 rows 3 cols","3 rows 2 cols","6 rows 1 col"],answer:"2 rows 3 cols",explanation:"repeat(3, 1fr) = 3 columns. 6 items / 3 columns = 2 rows. Grid auto-creates rows."},
    {id:6,question:"How does the item align?\n\n<style>\n  .container {\n    display: flex;\n    align-items: center;\n    height: 200px;\n  }\n</style>",options:["Top","Bottom","Center vertically","Stretch"],answer:"Center vertically",explanation:"align-items controls cross-axis (vertical in row). center = items centered vertically in 200px container."},
    {id:7,question:"What happens with flex-wrap: wrap?\n\n<style>\n  .container {\n    display: flex;\n    flex-wrap: wrap;\n    width: 200px;\n  }\n  .item { width: 100px; }\n</style>\n<!-- 4 items -->",options:["All overflow","2 items per row","4 items per row","1 item per row"],answer:"2 items per row",explanation:"Each item is 100px, container is 200px. 2 items fit per row. With wrap, remaining wrap to next row."},
    {id:8,question:"What is the item's width?\n\n<style>\n  .item {\n    grid-column: 1 / 3;\n  }\n  .grid {\n    display: grid;\n    grid-template-columns: 100px 100px 100px;\n  }\n</style>",options:["100px","200px","300px","auto"],answer:"200px",explanation:"grid-column: 1 / 3 spans from column line 1 to 3 = 2 columns × 100px = 200px."},
    {id:9,question:"What does place-items: center do?\n\n<style>\n  .grid {\n    display: grid;\n    place-items: center;\n    height: 200px;\n  }\n</style>",options:["Horizontal only","Vertical only","Both horizontally and vertically","Nothing"],answer:"Both horizontally and vertically",explanation:"place-items is shorthand for align-items and justify-items. center = center on both axes."},
    {id:10,question:"What is the gap between items?\n\n<style>\n  .flex {\n    display: flex;\n    gap: 10px 20px;\n  }\n</style>",options:["10px everywhere","20px everywhere","10px row, 20px column","row-gap 10px, column-gap 20px"],answer:"row-gap 10px, column-gap 20px",explanation:"gap: row-gap column-gap. gap: 10px 20px = row-gap 10px, column-gap 20px."},
  ]},
  { id:"htmlcss-out-box", name:"Output: Box Model & Positioning", icon:"💻", difficulty:"Medium", category:"CSS", questions:[
    {id:1,question:"What is the total height?\n\n<style>\n  .box {\n    height: 100px;\n    padding: 10px;\n    border: 5px solid black;\n    margin: 20px;\n    box-sizing: content-box;\n  }\n</style>",options:["100px","130px","150px","170px"],answer:"130px",explanation:"content-box: rendered height = height + padding-top + padding-bottom + border-top + border-bottom = 100 + 10 + 10 + 5 + 5 = 130px. Margin doesn't count in element height."},
    {id:2,question:"What position does this create?\n\n<style>\n  .box {\n    position: relative;\n    top: 20px;\n    left: 10px;\n  }\n</style>",options:["Removes from flow","Fixed to viewport","Offset from normal position, stays in flow","Fixed to parent"],answer:"Offset from normal position, stays in flow",explanation:"position: relative moves element visually but its original space is preserved in the document flow."},
    {id:3,question:"What happens here?\n\n<style>\n  .parent { position: relative; }\n  .child {\n    position: absolute;\n    top: 0;\n    right: 0;\n  }\n</style>",options:["Fixed to viewport","Top-right of document","Top-right of .parent","Top-right of body"],answer:"Top-right of .parent",explanation:"Absolute element positions relative to nearest positioned ancestor. .parent has position:relative — child goes to its top-right."},
    {id:4,question:"What is the stacking order?\n\n<style>\n  .a { position: relative; z-index: 1; }\n  .b { position: relative; z-index: 2; }\n  .c { position: relative; z-index: 3; }\n</style>",options:["a on top","b on top","c on top","Same level"],answer:"c on top",explanation:"Higher z-index = closer to viewer. c has z-index:3, highest. Order from back to front: a, b, c."},
    {id:5,question:"What is the margin between two divs?\n\n<style>\n  .a { margin-bottom: 20px; }\n  .b { margin-top: 30px; }\n</style>\n<div class='a'></div>\n<div class='b'></div>",options:["50px","30px","20px","10px"],answer:"30px",explanation:"Margin collapsing: vertical margins collapse to largest value. max(20px, 30px) = 30px between elements."},
    {id:6,question:"Which element is taken out of document flow?\n\n<style>\n  .a { position: static; }\n  .b { position: relative; }\n  .c { position: absolute; }\n  .d { float: left; }\n</style>",options:["a and b","b and d","c only","c and d"],answer:"c and d",explanation:"position:absolute and float both remove element from normal document flow. static and relative remain in flow."},
    {id:7,question:"What is the output?\n\n<style>\n  .box {\n    width: 100px;\n    overflow: hidden;\n  }\n</style>\n<div class='box'>VeryLongTextThatOverflows</div>",options:["Shows all text","Text clips at 100px","Text wraps","Error"],answer:"Text clips at 100px",explanation:"overflow:hidden clips content that extends beyond element's boundary. Text is cut off at 100px width."},
    {id:8,question:"What does this do to .child?\n\n<style>\n  .parent {\n    display: flex;\n    justify-content: center;\n    align-items: center;\n  }\n  .child { margin: auto; }\n</style>",options:["No effect","Pushes to corner","Centers perfectly","Stretches"],answer:"Centers perfectly",explanation:"margin:auto on flex item absorbs available space in all directions — centers the item perfectly in flex container."},
    {id:9,question:"What is the output?\n\n<style>\n  .sticky {\n    position: sticky;\n    top: 0;\n  }\n</style>",options:["Always fixed","Removes from flow","Relative until scrolled to top, then sticks","Fixed to parent"],answer:"Relative until scrolled to top, then sticks",explanation:"sticky: behaves like relative until scroll threshold (top:0) reached, then acts like fixed relative to scroll container."},
    {id:10,question:"What happens with display: none vs visibility: hidden?\n\n<style>\n  .a { display: none; }\n  .b { visibility: hidden; }\n</style>\n<div class='a'>A</div>\n<div class='b'>B</div>\n<div>C</div>",options:["A and B invisible, C moves up","A invisible C moves up, B invisible B space stays","Both take space","Neither works"],answer:"A invisible C moves up, B invisible B space stays",explanation:"display:none removes from flow (C moves up). visibility:hidden hides visually but preserves space (gap where B was)."},
  ]},
  { id:"htmlcss-out-html", name:"Output: HTML Behavior", icon:"💻", difficulty:"Easy", category:"HTML", questions:[
    {id:1,question:"What does this render?\n\n<p>Hello &amp; World</p>",options:["Hello &amp; World","Hello & World","Hello World","Error"],answer:"Hello & World",explanation:"&amp; is HTML entity for & character. Browser renders &amp; as literal & symbol."},
    {id:2,question:"What is the tab order?\n\n<button tabindex='2'>B</button>\n<button tabindex='1'>A</button>\n<button tabindex='3'>C</button>",options:["B A C","A B C","C B A","A C B"],answer:"A B C",explanation:"tabindex determines keyboard tab order. Lower positive values come first: 1(A), 2(B), 3(C)."},
    {id:3,question:"What does this form do on submit?\n\n<form action='/submit' method='GET'>\n  <input name='q' value='hello'>\n</form>",options:["POST to /submit","GET /submit with body","Navigates to /submit?q=hello","Error"],answer:"Navigates to /submit?q=hello",explanation:"GET method appends form data as URL query string. Action URL + ? + name=value pairs."},
    {id:4,question:"How many heading levels does HTML support?",options:["3","4","6","8"],answer:"6",explanation:"HTML has h1 through h6 — six heading levels. h1 most important, h6 least."},
    {id:5,question:"What does this output?\n\n<ul>\n  <li>One</li>\n  <li>Two</li>\n</ul>",options:["1. One 2. Two","• One • Two","One Two","- One - Two"],answer:"• One • Two",explanation:"ul = unordered list — default browser style uses bullet points (•). ol would give numbered list."},
    {id:6,question:"What is the difference?\n\n<b>Bold</b> vs <strong>Strong</strong>",options:["No difference","b: visual only; strong: semantic importance","strong is newer","b is deprecated"],answer:"b: visual only; strong: semantic importance",explanation:"<b> is presentational — bold styling. <strong> is semantic — indicates strong importance. Screen readers emphasize <strong>."},
    {id:7,question:"What does meta charset do?\n\n<meta charset='UTF-8'>",options:["Sets language","Defines character encoding — how text bytes are interpreted","SEO tag","CSS import"],answer:"Defines character encoding — how text bytes are interpreted",explanation:"charset defines how bytes in HTML file are decoded to characters. UTF-8 supports all Unicode characters."},
    {id:8,question:"What renders differently?\n\n<em>text</em> vs <i>text</i>",options:["Nothing — both italic","em: semantic stress; i: visual italic only","i is deprecated","em is newer"],answer:"em: semantic stress; i: visual italic only",explanation:"<em> semantic emphasis — screen readers stress it. <i> is presentational italic (foreign words, technical terms, no emphasis)."},
    {id:9,question:"What does defer do?\n\n<script src='app.js' defer></script>",options:["Blocks parsing","Loads async, executes after DOM parsed","Executes immediately","Ignores script"],answer:"Loads async, executes after DOM parsed",explanation:"defer: script downloads in parallel, executes after HTML fully parsed. Multiple defer scripts execute in order."},
    {id:10,question:"What is the output?\n\n<p>Hello\n   World</p>",options:["Hello\\n   World","Hello World","Hello   World","Error"],answer:"Hello World",explanation:"HTML collapses whitespace (spaces, newlines, tabs) to single space. Multiple spaces/newlines between words = single space."},
  ]},
  { id:"htmlcss-out-animations", name:"Output: Animations & Transforms", icon:"💻", difficulty:"Medium", category:"CSS", questions:[
    {id:1,question:"What does this produce?\n\n<style>\n  .box {\n    transform: translateX(50px);\n  }\n</style>",options:["Moves 50px down","Moves 50px right","Rotates 50deg","Scales by 50"],answer:"Moves 50px right",explanation:"translateX(50px) moves element 50px along X-axis (horizontally to the right)."},
    {id:2,question:"What is the result?\n\n<style>\n  .box {\n    transform: rotate(90deg);\n  }\n</style>",options:["Moves right","Scales up","Rotates clockwise 90 degrees","Rotates counter-clockwise"],answer:"Rotates clockwise 90 degrees",explanation:"rotate(90deg) rotates element 90 degrees clockwise. Negative values rotate counter-clockwise."},
    {id:3,question:"How long is the transition?\n\n<style>\n  .box {\n    transition: all 0.3s ease-in-out 0.1s;\n  }\n</style>",options:["0.3s","0.1s","0.4s","0.13s"],answer:"0.3s",explanation:"transition: property duration timing-function delay. Duration = 0.3s. Delay = 0.1s (starts after 0.1s). Total = 0.4s but duration is 0.3s."},
    {id:4,question:"What does fill-mode: forwards do?\n\n<style>\n  .box {\n    animation: slide 1s forwards;\n  }\n</style>",options:["Loops forward","Element stays at animation end state after finishing","Plays forward only","Resets to start"],answer:"Element stays at animation end state after finishing",explanation:"forwards: after animation completes, element retains the styles from the last keyframe (to {})."},
    {id:5,question:"What does this do to performance?\n\n<style>\n  .box {\n    transform: translateX(100px);\n    opacity: 0.5;\n  }\n</style>",options:["Slow — triggers reflow","Fast — GPU composited, no reflow","Medium speed","Depends on browser"],answer:"Fast — GPU composited, no reflow",explanation:"transform and opacity are GPU-composited properties — don't trigger layout or paint. Smooth 60fps animations."},
    {id:6,question:"What is the output?\n\n<style>\n  @keyframes fade {\n    from { opacity: 1; }\n    to { opacity: 0; }\n  }\n  .box { animation: fade 2s infinite alternate; }\n</style>",options:["Fades out once","Stays hidden","Continuously fades in and out","Fades in only"],answer:"Continuously fades in and out",explanation:"infinite = loops forever. alternate = reverses direction each cycle. Fades out (1→0), fades in (0→1), repeating."},
    {id:7,question:"What does transform-origin: top left do?\n\n<style>\n  .box {\n    transform-origin: top left;\n    transform: rotate(45deg);\n  }\n</style>",options:["Rotates from center","Rotates from top-left corner","Moves to top-left","Scales from top-left"],answer:"Rotates from top-left corner",explanation:"transform-origin sets the pivot point. top left = 0% 0%. Element rotates around its top-left corner."},
    {id:8,question:"What does animation-iteration-count: 3 do?",options:["Plays 3ms","Plays 3 times then stops","Loops forever","Plays at speed 3"],answer:"Plays 3 times then stops",explanation:"animation-iteration-count: 3 plays the animation exactly 3 times. Use infinite to loop forever."},
    {id:9,question:"What does scale(2) do?\n\n<style>\n  .box { transform: scale(2); }\n</style>",options:["Width doubles only","Height doubles only","Both width and height double","Moves 2px"],answer:"Both width and height double",explanation:"scale(2) = scaleX(2) scaleY(2). Both dimensions doubled. scale(2, 1) would only double width."},
    {id:10,question:"What is the rendering difference?\n\n.a { left: 100px; } (position:absolute)\n.b { transform: translateX(100px); }",options:["Same performance","left triggers layout; transform uses GPU — transform faster","transform triggers layout","Both same performance"],answer:"left triggers layout; transform uses GPU — transform faster",explanation:"Changing left/top triggers reflow (layout recalculation). transform bypasses layout/paint — GPU only. Use transform for animations."},
  ]},
];

// ══════════════════════════════════════════════════
// HTML/CSS — BUG FINDER (🐛)
// ══════════════════════════════════════════════════
export const HTMLCSS_BUG_TOPICS: Topic[] = [
  { id:"htmlcss-bug-css", name:"Bug: CSS", icon:"🐛", difficulty:"Easy", category:"CSS", questions:[
    {id:1,question:"Find the bug:\n\n.box {\n  width: 100%;\n  padding: 20px;\n  box-sizing: content-box;\n  /* inside a 300px parent */\n}",options:["No bug","Overflow — content-box adds padding ON TOP of 100% width = 340px total","Wrong padding","Missing border"],answer:"Overflow — content-box adds padding ON TOP of 100% width = 340px total",explanation:"content-box: total = 100% + 40px padding = 340px > 300px parent. Fix: box-sizing: border-box or width: calc(100% - 40px)."},
    {id:2,question:"Find the bug:\n\n.container {\n  display: flex;\n}\n.item {\n  width: 100px;\n  margin: auto;\n}",options:["No bug","margin: auto centers the flex item — but this is actually valid and works","flex-direction wrong","Item too wide"],answer:"No bug",explanation:"margin: auto on flex item absorbs available space — perfectly valid for centering. No bug here."},
    {id:3,question:"Find the bug:\n\np {\n  color: red;\n}\np {\n  color: blue;\n  color: green;\n}\n<p>Hello</p>",options:["Multiple declarations invalid","No bug — green wins (last declaration)","Red wins","Blue wins"],answer:"No bug — green wins (last declaration)",explanation:"Same property declared twice — last one wins (cascade). green comes after blue, so green applies. No bug."},
    {id:4,question:"Find the bug:\n\n.box {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n}",options:["No bug","Top-left corner at center, not element center — need transform: translate(-50%,-50%)","Wrong values","Missing parent"],answer:"Top-left corner at center, not element center — need transform: translate(-50%,-50%)",explanation:"top:50% left:50% positions top-left corner at center. To truly center: add transform: translate(-50%, -50%)."},
    {id:5,question:"Find the bug:\n\n.nav a {\n  display: inline;\n  width: 100px;\n  height: 40px;\n}",options:["No bug","width/height ignored on inline elements — use inline-block or block","Wrong selector","Missing color"],answer:"width/height ignored on inline elements — use inline-block or block",explanation:"Inline elements ignore width and height. Use display: inline-block or display: block to apply dimensions."},
    {id:6,question:"Find the bug:\n\n.container {\n  display: flex;\n  justify-items: center;\n}",options:["No bug","justify-items doesn't work on flex — use justify-content","Wrong value","Missing items"],answer:"justify-items doesn't work on flex — use justify-content",explanation:"justify-items is for Grid, not Flexbox. For flex main-axis alignment use justify-content: center."},
    {id:7,question:"Find the bug:\n\n.box {\n  transition: width 0.3s;\n  width: 100px;\n}\n.box:hover {\n  width: auto;\n}",options:["No bug","Cannot transition to 'auto' — transition won't animate","Wrong duration","Hover syntax"],answer:"Cannot transition to 'auto' — transition won't animate",explanation:"CSS cannot animate to/from auto values — they're not calculable. Use max-width or specific pixel/% values instead."},
    {id:8,question:"Find the bug:\n\n#header {\n  z-index: 999;\n}\n.modal {\n  z-index: 1000;\n  position: static;\n}",options:["No bug","z-index ignored on position:static — modal won't stack above header","Wrong z-index","Missing display"],answer:"z-index ignored on position:static — modal won't stack above header",explanation:"z-index only works on positioned elements (relative, absolute, fixed, sticky). position:static ignores z-index."},
    {id:9,question:"Find the bug:\n\n.grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr;\n  gap: 10px 20px 15px;\n}",options:["No bug","gap takes max 2 values: row-gap column-gap — third value invalid","Wrong columns","fr unit wrong"],answer:"gap takes max 2 values: row-gap column-gap — third value invalid",explanation:"gap shorthand: gap: row-gap column-gap (1 or 2 values). Three values are invalid — browser may ignore or error."},
    {id:10,question:"Find the bug:\n\n.parent {\n  overflow: hidden;\n}\n.child {\n  position: sticky;\n  top: 0;\n}",options:["No bug","overflow:hidden on parent breaks sticky — sticky won't work","Wrong top","Missing height"],answer:"overflow:hidden on parent breaks sticky — sticky won't work",explanation:"position:sticky requires a scrollable ancestor. overflow:hidden/auto/scroll on parent makes it the scroll container, often breaking sticky behavior."},
  ]},
  { id:"htmlcss-bug-layout", name:"Bug: Layout", icon:"🐛", difficulty:"Medium", category:"CSS", questions:[
    {id:1,question:"Find the bug:\n\n.container {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n}\n/* Items not centering horizontally */",options:["No bug","In column direction, align-items controls horizontal — this is correct","justify-content wrong","Missing height"],answer:"No bug",explanation:"In flex-direction:column, main axis is vertical (justify-content) and cross axis is horizontal (align-items:center). Horizontal centering works."},
    {id:2,question:"Find the bug:\n\n.container {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, 200px);\n  /* Items not filling available space */\n}",options:["No bug","auto-fill with fixed px won't stretch — use minmax(200px, 1fr)","Wrong repeat","Wrong px"],answer:"auto-fill with fixed px won't stretch — use minmax(200px, 1fr)",explanation:"auto-fill with fixed 200px creates columns but won't expand. Use repeat(auto-fill, minmax(200px, 1fr)) to fill space."},
    {id:3,question:"Find the bug:\n\n.flex-child {\n  flex: 0 0 200px;\n  /* Expected to grow with available space */\n}",options:["No bug","flex-grow:0 prevents growing — use flex: 1 0 200px or flex: 1","Wrong flex-basis","Missing flex"],answer:"flex-grow:0 prevents growing — use flex: 1 0 200px or flex: 1",explanation:"flex: 0 0 200px = grow:0 shrink:0 basis:200px. grow:0 means item won't expand. Change first value to 1."},
    {id:4,question:"Find the bug:\n\n.two-column {\n  display: grid;\n  grid-template-columns: 300px auto;\n  /* Second column not filling remaining space */\n}",options:["No bug","auto takes content size, not remaining space — use 1fr instead","Wrong 300px","Grid syntax wrong"],answer:"auto takes content size, not remaining space — use 1fr instead",explanation:"auto in grid = content size. 1fr takes remaining available space. Use: grid-template-columns: 300px 1fr."},
    {id:5,question:"Find the bug:\n\n.card {\n  display: flex;\n  flex-direction: column;\n}\n.card-footer {\n  margin-top: auto;\n  /* Footer not at bottom */\n}",options:["No bug — works correctly","margin-top:auto on flex child pushes it to bottom — this works if card has defined height","Wrong property","Flex direction wrong"],answer:"No bug — works correctly",explanation:"margin-top: auto on flex child pushes it down to the bottom of the flex container. Classic footer-to-bottom pattern. Works correctly."},
    {id:6,question:"Find the bug:\n\n.sidebar {\n  position: fixed;\n  width: 250px;\n}\n.main {\n  margin-left: 250px;\n}\n/* Main content overlapping sidebar */",options:["No bug","fixed element removed from flow — main needs margin-left equal to sidebar width","Wrong position","Wrong margin"],answer:"No bug",explanation:"position:fixed removes from flow. main needs margin-left:250px to not overlap. The code already has margin-left:250px — no bug."},
    {id:7,question:"Find the bug:\n\n.container {\n  width: 600px;\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  column-gap: 20px;\n}\n/* Columns wider than expected */",options:["No bug","No bug — 1fr accounts for gap automatically","Gap not subtracted from fr","Wrong width"],answer:"No bug — 1fr accounts for gap automatically",explanation:"fr units distribute available space AFTER gaps are accounted for. 600px - 20px gap = 580px, split: 290px each. No bug."},
    {id:8,question:"Find the bug:\n\n.image-container {\n  width: 300px;\n  height: 200px;\n}\n.image-container img {\n  width: 100%;\n  height: 100%;\n  /* Image looks stretched */\n}",options:["No bug","Missing object-fit: cover — 100%/100% stretches image distorting aspect ratio","Wrong dimensions","img syntax"],answer:"Missing object-fit: cover — 100%/100% stretches image distorting aspect ratio",explanation:"width:100% height:100% forces image to fill container distorting aspect ratio. Add object-fit: cover to maintain ratio."},
    {id:9,question:"Find the bug:\n\n.flex-container {\n  display: flex;\n  align-content: center;\n  /* Single row not centering vertically */\n}",options:["No bug","align-content works with multi-line flex — use align-items for single row","Wrong property","Missing height"],answer:"align-content works with multi-line flex — use align-items for single row",explanation:"align-content affects multi-line flex containers. For single row vertical centering use align-items: center."},
    {id:10,question:"Find the bug:\n\n.grid-item {\n  grid-column: 1 / -1;\n}\n.grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n}",options:["No bug — spans full width","grid-column on item defined before grid on container — ordering issue in CSS","Wrong span","Negative index wrong"],answer:"No bug — spans full width",explanation:"grid-column: 1 / -1 spans from first to last line — full width. -1 refers to last explicit column line. CSS order doesn't matter. No bug."},
  ]},
  { id:"htmlcss-bug-html", name:"Bug: HTML", icon:"🐛", difficulty:"Easy", category:"HTML", questions:[
    {id:1,question:"Find the bug:\n\n<img src='photo.jpg'>",options:["No bug","Missing alt attribute — accessibility issue and invalid HTML","Wrong src","Missing closing tag"],answer:"Missing alt attribute — accessibility issue and invalid HTML",explanation:"alt attribute required for accessibility — screen readers read it. Empty alt='' acceptable for decorative images. Missing alt is an error."},
    {id:2,question:"Find the bug:\n\n<form>\n  <label>Name</label>\n  <input type='text' name='name'>\n</form>",options:["No bug","label not associated with input — missing for/id link","Wrong input type","Missing action"],answer:"label not associated with input — missing for/id link",explanation:"label needs for='name' and input needs id='name' to be associated. Without link, clicking label doesn't focus input."},
    {id:3,question:"Find the bug:\n\n<a href='https://example.com' target='_blank'>Visit</a>",options:["No bug","Missing rel='noopener noreferrer' — security vulnerability","Wrong href","Wrong target"],answer:"Missing rel='noopener noreferrer' — security vulnerability",explanation:"target='_blank' without rel='noopener noreferrer' — opened page can access window.opener. Add rel='noopener noreferrer' for security."},
    {id:4,question:"Find the bug:\n\n<!DOCTYPE html>\n<html>\n  <body>\n    <h1>Title</h1>\n  </body>\n</html>",options:["No bug","Missing <head> tag — title, meta, CSS links go in head","Wrong DOCTYPE","Missing lang"],answer:"Missing <head> tag — title, meta, CSS links go in head",explanation:"<head> should contain <title>, <meta charset>, CSS links. Though browsers may handle it, omitting <head> is invalid HTML."},
    {id:5,question:"Find the bug:\n\n<button onclick='submitForm()'>Submit</button>\n<button>Cancel</button>\n<!-- Inside a <form> -->",options:["No bug","Cancel button will also submit — missing type='button'","Wrong onclick","Wrong tag"],answer:"Cancel button will also submit — missing type='button'",explanation:"Default button type inside form is 'submit'. Cancel button needs type='button' to prevent form submission."},
    {id:6,question:"Find the bug:\n\n<table>\n  <tr><td>Name</td><td>Age</td></tr>\n  <tr><td>Ali</td><td>25</td></tr>\n</table>",options:["No bug","Header row should use <th> not <td> — accessibility and semantics","Wrong structure","Missing caption"],answer:"Header row should use <th> not <td> — accessibility and semantics",explanation:"<th> = table header cell. Screen readers announce headers for each data cell. <td> for headers loses semantic meaning."},
    {id:7,question:"Find the bug:\n\n<input type='email' required>\n<input type='password' required>\n<button>Login</button>\n<!-- No form tag -->",options:["No bug","Inputs outside form — required validation and submit won't work properly","Wrong input types","Wrong button"],answer:"Inputs outside form — required validation and submit won't work properly",explanation:"Inputs need to be inside <form> for required validation, form submission, and accessibility. Wrap in <form action='...' method='POST'>."},
    {id:8,question:"Find the bug:\n\n<p>This is a paragraph\n<p>This is another paragraph</p>",options:["No bug","First <p> missing closing tag — invalid HTML though browsers handle it","Wrong nesting","Missing div"],answer:"First <p> missing closing tag — invalid HTML though browsers handle it",explanation:"First <p> missing </p>. Browsers auto-close it but it's invalid HTML. Always close tags for maintainable, valid markup."},
    {id:9,question:"Find the bug:\n\n<h1>Main Title</h1>\n<h3>Subtitle</h3>\n<h2>Section</h2>",options:["No bug","Heading hierarchy skipped — h1 to h3 skips h2, bad for accessibility","Wrong order","Missing h4"],answer:"Heading hierarchy skipped — h1 to h3 skips h2, bad for accessibility",explanation:"Headings should go in order: h1, h2, h3. Skipping from h1 to h3 breaks document outline and screen reader navigation."},
    {id:10,question:"Find the bug:\n\n<div onclick='handleClick()'>\n  Click me\n</div>",options:["No bug","Div not keyboard accessible — use <button> instead","Wrong event","Wrong tag name"],answer:"Div not keyboard accessible — use <button> instead",explanation:"Clickable div not focusable or keyboard-operable by default. Use <button> which is keyboard accessible. Or add tabindex='0' and keydown handler to div."},
  ]},
  { id:"htmlcss-bug-responsive", name:"Bug: Responsive & Animations", icon:"🐛", difficulty:"Hard", category:"CSS", questions:[
    {id:1,question:"Find the bug:\n\n<meta name='viewport' content='width=1200'>",options:["No bug","Fixed width viewport breaks responsive — use width=device-width, initial-scale=1","Wrong meta","Missing initial-scale"],answer:"Fixed width viewport breaks responsive — use width=device-width, initial-scale=1",explanation:"width=1200 forces viewport to 1200px regardless of device. Mobile sites look zoomed out. Use width=device-width."},
    {id:2,question:"Find the bug:\n\n@media (max-width: 768px) {\n  .container { width: 100%; }\n}\n@media (max-width: 1024px) {\n  .container { width: 80%; }\n}\n/* Mobile-first approach */",options:["No bug","Wrong order — larger breakpoint defined first overrides smaller","Media syntax wrong","Wrong values"],answer:"Wrong order — larger breakpoint defined first overrides smaller",explanation:"With max-width, write larger values first or smaller last. 1024px rule should come before 768px to not override it. Or use min-width mobile-first."},
    {id:3,question:"Find the bug:\n\n.text {\n  font-size: 5vw;\n}\n/* On a 2560px monitor, font would be 128px */",options:["No bug","Unconstrained vw — use clamp() for min/max bounds","Wrong unit","Missing px fallback"],answer:"Unconstrained vw — use clamp() for min/max bounds",explanation:"5vw scales without limits. On large screens = huge text. Use clamp(1rem, 2vw, 2rem) to set minimum and maximum bounds."},
    {id:4,question:"Find the bug:\n\n.card {\n  width: 300px;\n}\n@media (max-width: 600px) {\n  .card {\n    width: 100%;\n  }\n}",options:["No bug","On mobile, fixed 300px may overflow — but media query fixes it to 100%. No bug","Wrong breakpoint","Mobile-first wrong"],answer:"No bug",explanation:"Desktop: 300px. Mobile (≤600px): 100%. The media query correctly overrides for small screens. No bug."},
    {id:5,question:"Find the bug:\n\n@keyframes slide {\n  0% { left: -100px; }\n  100% { left: 0; }\n}\n.box {\n  position: relative;\n  animation: slide 0.5s;\n}",options:["No bug","Animating 'left' triggers layout reflow — use transform: translateX instead","Wrong keyframes","Wrong position"],answer:"Animating 'left' triggers layout reflow — use transform: translateX instead",explanation:"Changing left/top triggers reflow on every frame — poor performance. Use transform: translateX(-100px) → translateX(0) for GPU-composited animation."},
    {id:6,question:"Find the bug:\n\n.button {\n  transition: background-color 0.3s;\n}\n.button:hover {\n  background: linear-gradient(red, blue);\n}",options:["No bug","Gradients cannot be transitioned — transition won't animate","Wrong transition","Wrong hover"],answer:"Gradients cannot be transitioned — transition won't animate",explanation:"CSS cannot interpolate between gradient values. Transition has no effect. Use background-color or opacity trick instead."},
    {id:7,question:"Find the bug:\n\n* {\n  animation-duration: 0s !important;\n  transition-duration: 0s !important;\n}\n/* Trying to respect prefers-reduced-motion */",options:["No bug","Should use @media (prefers-reduced-motion) not universal selector always","Wrong properties","Missing media query"],answer:"Should use @media (prefers-reduced-motion) not universal selector always",explanation:"This disables ALL animations always. Wrap in @media (prefers-reduced-motion: reduce) to only disable when user prefers it."},
    {id:8,question:"Find the bug:\n\n.box {\n  width: 200px;\n  transition: width 0.3s;\n}\n.box:hover { width: 300px; }\n.box:hover .text { opacity: 1; }\n/* .text doesn't animate */",options:["No bug","transition only on .box — .text needs its own transition","Wrong transition","Wrong opacity"],answer:"transition only on .box — .text needs its own transition",explanation:".text needs transition: opacity 0.3s on .text itself. Transition only applies to the element it's declared on."},
    {id:9,question:"Find the bug:\n\n.grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(0, 1fr));\n}",options:["No bug","minmax(0, 1fr) — min of 0 creates very narrow columns on small screens","Wrong auto-fit","Wrong 1fr"],answer:"minmax(0, 1fr) — min of 0 creates very narrow columns on small screens",explanation:"minmax(0, 1fr) allows columns to shrink to 0. Use minmax(150px, 1fr) or similar minimum for responsive cards."},
    {id:10,question:"Find the bug:\n\n.element {\n  will-change: transform, opacity, width, height, color, background;\n}",options:["No bug","Over-using will-change — too many properties wastes GPU memory and hurts performance","Syntax wrong","Missing values"],answer:"Over-using will-change — too many properties wastes GPU memory and hurts performance",explanation:"will-change creates GPU layers — using on too many properties wastes VRAM. Only apply to 1-2 actually animating properties."},
  ]},
];

// ══════════════════════════════════════════════════
// HTML/CSS — FILL IN THE BLANK (⬜)
// ══════════════════════════════════════════════════
export const HTMLCSS_FILL_TOPICS: Topic[] = [
  { id:"htmlcss-fill-selectors", name:"Fill: Selectors & Specificity", icon:"⬜", difficulty:"Easy", category:"CSS", questions:[
    {id:1,question:"Complete to select all direct children:\n\n.parent _____ .child {\n  color: red;\n}",options:["  (space)"," > "," ~ "," + "],answer:" > ",explanation:"Child combinator > selects direct children only. Space (descendant) selects all nested descendants."},
    {id:2,question:"Complete to select on hover:\n\nbutton_____:hover {\n  background: blue;\n}",options:[" :: "," : ","."," # "],answer:" : ",explanation:":hover is a pseudo-class — use single colon. ::before/::after use double colon (pseudo-elements)."},
    {id:3,question:"Complete to target adjacent sibling:\n\nh2 _____ p {\n  margin-top: 0;\n}",options:[">"," + "," ~ "," * "],answer:" + ",explanation:"Adjacent sibling combinator + selects the immediately following sibling. h2 + p = first p after h2."},
    {id:4,question:"Complete the attribute selector:\n\na[href_____='https'] {\n  color: green;\n}",options:["=","^=","$=","*="],answer:"^=",explanation:"^= selects attributes that START with value. a[href^='https'] selects all https links."},
    {id:5,question:"Complete to select nth child:\n\nli:_____-child(odd) {\n  background: #eee;\n}",options:["first","last","nth","every"],answer:"nth",explanation:":nth-child(odd) selects odd-numbered children (1,3,5...). Also accepts numbers: :nth-child(3), formulas: :nth-child(2n)."},
    {id:6,question:"Complete the CSS variable declaration:\n\n:root {\n  _____primary-color: #3b82f6;\n}\n\n.btn {\n  color: var(_____primary-color);\n}",options:["-- / --","- / -","var / var","# / #"],answer:"-- / --",explanation:"CSS custom properties declared with -- prefix: --primary-color. Referenced with var(--primary-color)."},
    {id:7,question:"Complete to target first child:\n\np:_____-child {\n  font-weight: bold;\n}",options:["first","1st","one","begin"],answer:"first",explanation:":first-child selects element that is first child of its parent. :last-child selects last. :first-of-type selects first of that type."},
    {id:8,question:"Complete to select all paragraphs NOT with class active:\n\np:_____(._____) {\n  opacity: 0.5;\n}",options:["not / active","exclude / active","not / .active","without / active"],answer:"not / .active",explanation:":not(.active) excludes elements with class active. p:not(.active) = all paragraphs without active class."},
    {id:9,question:"Complete to match substring in attribute:\n\n[class_____='card'] {\n  border: 1px solid;\n}\n/* Matches card, card-header, my-card */",options:["^=","$=","*=","~="],answer:"*=",explanation:"*= matches if attribute contains the value anywhere. [class*='card'] matches 'card', 'card-header', 'my-card'."},
    {id:10,question:"Complete to combine selectors:\n\nh1, h2, h3, h4, h5, h6 {\n  font-family: _____;\n}\n/* All headings get same font */",options:["inherit","sans-serif","'Arial'","All of above valid"],answer:"All of above valid",explanation:"inherit, named fonts, or font stacks all valid. Comma groups selectors — all matched elements share same styles."},
  ]},
  { id:"htmlcss-fill-layout", name:"Fill: Flexbox & Grid", icon:"⬜", difficulty:"Medium", category:"CSS", questions:[
    {id:1,question:"Complete to center content:\n\n.container {\n  display: flex;\n  _____: center;\n  _____: center;\n  height: 100vh;\n}",options:["justify-content / align-items","align-items / justify-content","justify / align","flex-justify / flex-align"],answer:"justify-content / align-items",explanation:"justify-content: center = main axis (horizontal). align-items: center = cross axis (vertical). Together = perfect centering."},
    {id:2,question:"Complete to make items wrap:\n\n.flex {\n  display: flex;\n  flex-_____: wrap;\n}",options:["direction","order","wrap","flow"],answer:"wrap",explanation:"flex-wrap: wrap allows items to wrap to next line when they don't fit. Default is nowrap."},
    {id:3,question:"Complete responsive grid:\n\n.grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, _____(200px, 1fr));\n}",options:["max","min","clamp","minmax"],answer:"minmax",explanation:"minmax(200px, 1fr) — columns minimum 200px, maximum 1fr. auto-fit fills available space. Responsive without media queries."},
    {id:4,question:"Complete to span 2 columns:\n\n.wide-item {\n  grid-column: span _____;\n}",options:["1","2","full","all"],answer:"2",explanation:"grid-column: span 2 makes item span 2 columns. Shorthand for grid-column: auto / span 2."},
    {id:5,question:"Complete the grid areas:\n\n.container {\n  display: grid;\n  grid-template-areas:\n    '_____  main'\n    'sidebar main';\n}\n.header { grid-area: _____; }",options:["header / header","nav / nav","top / top","head / head"],answer:"header / header",explanation:"grid-template-areas defines named zones. grid-area: header places element in header zone."},
    {id:6,question:"Complete to push item to end:\n\n.flex-container { display: flex; }\n.push-right {\n  margin-_____: auto;\n}",options:["right","left","top","bottom"],answer:"left",explanation:"margin-left: auto on flex item absorbs all available space to the left — pushes item to the far right."},
    {id:7,question:"Complete the flex shorthand:\n\n.item {\n  flex: _____ 0 150px;\n  /* Can grow, cannot shrink, 150px base */\n}",options:["0","1","auto","none"],answer:"1",explanation:"flex: grow shrink basis. flex: 1 0 150px = can grow (1), cannot shrink (0), starts at 150px."},
    {id:8,question:"Complete to control item order:\n\n.first-visually {\n  _____: -1;\n}\n/* Appears first regardless of DOM order */",options:["z-index","flex-order","order","index"],answer:"order",explanation:"order property changes visual order of flex/grid items. Default 0 — lower values appear first."},
    {id:9,question:"Complete the implicit grid:\n\n.grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  grid-auto-_____: 100px;\n}",options:["height","size","rows","columns"],answer:"rows",explanation:"grid-auto-rows: 100px sets height of auto-created rows (implicit rows beyond defined template)."},
    {id:10,question:"Complete for equal columns:\n\n.grid {\n  display: grid;\n  grid-template-columns: repeat(4, _____fr);\n}",options:["0","auto","1","equal"],answer:"1",explanation:"repeat(4, 1fr) creates 4 equal-width columns. 1fr = 1 fraction of available space. All equal since same fraction."},
  ]},
  { id:"htmlcss-fill-responsive", name:"Fill: Responsive & Animations", icon:"⬜", difficulty:"Medium", category:"CSS", questions:[
    {id:1,question:"Complete the media query:\n\n@_____(max-width: 768px) {\n  .nav { display: none; }\n}",options:["screen","query","media","breakpoint"],answer:"media",explanation:"@media rule creates media query. @media (max-width: 768px) applies styles on screens ≤768px."},
    {id:2,question:"Complete fluid font size:\n\n.title {\n  font-size: _____(1rem, 2.5vw, 3rem);\n}",options:["min","max","clamp","range"],answer:"clamp",explanation:"clamp(min, preferred, max) — never smaller than 1rem, scales with viewport, never larger than 3rem."},
    {id:3,question:"Complete the transition:\n\n.btn {\n  background: blue;\n  transition: background 0.3s _____-in-out;\n}",options:["easy","ease","smooth","linear"],answer:"ease",explanation:"ease-in-out is a timing function — starts slow, speeds up, slows down. Other options: ease, linear, ease-in, ease-out."},
    {id:4,question:"Complete the keyframe animation:\n\n@keyframes fadeIn {\n  _____ { opacity: 0; }\n  _____ { opacity: 1; }\n}",options:["start / end","from / to","0 / 100","begin / finish"],answer:"from / to",explanation:"@keyframes uses from (0%) and to (100%), or percentage values: 0% { } 100% { }."},
    {id:5,question:"Complete to apply animation:\n\n.box {\n  animation-name: bounce;\n  animation-duration: _____;\n  animation-iteration-count: infinite;\n}",options:["1","1px","1s","1%"],answer:"1s",explanation:"animation-duration takes a time value — seconds (s) or milliseconds (ms). 1s = 1 second duration."},
    {id:6,question:"Complete to respect user preferences:\n\n@media (prefers-reduced-_____: reduce) {\n  * { animation: none !important; }\n}",options:["animation","motion","transition","movement"],answer:"motion",explanation:"prefers-reduced-motion media feature detects if user has requested reduced animation in OS settings."},
    {id:7,question:"Complete the transform:\n\n.centered {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(_____%, _____%); \n}",options:["-50 / -50","50 / 50","-100 / -100","0 / 0"],answer:"-50 / -50",explanation:"translate(-50%, -50%) shifts element back by half its own width and height — truly centers it at the anchor point."},
    {id:8,question:"Complete for smooth scroll:\n\nhtml {\n  scroll-behavior: _____;\n}",options:["smooth","auto","ease","animated"],answer:"smooth",explanation:"scroll-behavior: smooth enables animated scrolling for anchor links and JavaScript scroll methods."},
    {id:9,question:"Complete for aspect ratio box:\n\n.video-container {\n  aspect-ratio: _____ / _____;\n  width: 100%;\n}",options:["16 / 9","4 / 3","1 / 1","Any valid ratio"],answer:"Any valid ratio",explanation:"aspect-ratio accepts any ratio. 16/9 for widescreen video, 4/3 traditional, 1/1 for square. All valid."},
    {id:10,question:"Complete GPU-accelerated animation:\n\n@keyframes slide {\n  from { transform: _____(−100%); }\n  to { transform: _____(0); }\n}",options:["translateX / translateX","moveX / moveX","left / left","x / x"],answer:"translateX / translateX",explanation:"translateX() uses GPU compositing — no layout trigger. Animating left/top instead causes reflow every frame."},
  ]},
  { id:"htmlcss-fill-html", name:"Fill: HTML Structure", icon:"⬜", difficulty:"Easy", category:"HTML", questions:[
    {id:1,question:"Complete the HTML boilerplate:\n\n<!_____ html>\n<html lang='en'>\n  <head>\n    <meta charset='UTF-8'>\n    <title>Page</title>\n  </head>",options:["TYPE","DOCTYPE","doctype","document"],answer:"DOCTYPE",explanation:"<!DOCTYPE html> tells browser this is HTML5 document. Must be first line. Case-insensitive but uppercase convention."},
    {id:2,question:"Complete the image tag:\n\n<img src='photo.jpg' _____='A sunset photo'>",options:["title","description","alt","caption"],answer:"alt",explanation:"alt attribute provides alternative text for images — required for accessibility and shown when image fails to load."},
    {id:3,question:"Complete the link tag:\n\n<link _____ ='stylesheet' href='styles.css'>",options:["type","src","rel","href"],answer:"rel",explanation:"rel='stylesheet' tells browser the linked file is a CSS stylesheet. rel = relationship between current document and linked resource."},
    {id:4,question:"Complete semantic structure:\n\n<_____>\n  <nav>Navigation</nav>\n  <h1>Logo</h1>\n</_____>",options:["div / div","section / section","header / header","top / top"],answer:"header / header",explanation:"<header> is semantic element for page/section header — contains navigation, logo, headings. Better than <div class='header'>."},
    {id:5,question:"Complete the form:\n\n<form action='/login' _____='POST'>\n  <input type='text' name='username'>\n  <input type='password' name='password'>\n  <button type='submit'>Login</button>\n</form>",options:["type","action","method","submit"],answer:"method",explanation:"method='POST' sends form data in request body — appropriate for sensitive data. GET appends to URL."},
    {id:6,question:"Complete the table structure:\n\n<table>\n  <_____>\n    <tr><th>Name</th><th>Age</th></tr>\n  </_____>\n  <tbody>\n    <tr><td>Ali</td><td>25</td></tr>\n  </tbody>\n</table>",options:["thead / thead","header / header","th / th","head / head"],answer:"thead / thead",explanation:"<thead> wraps header rows. <tbody> wraps data rows. <tfoot> for footer rows. Semantic grouping for accessibility."},
    {id:7,question:"Complete for external link opening in new tab:\n\n<a href='https://example.com'\n   _____='_blank'\n   rel='noopener noreferrer'>Link</a>",options:["rel","src","open","target"],answer:"target",explanation:"target='_blank' opens link in new tab. Always add rel='noopener noreferrer' for security when using _blank."},
    {id:8,question:"Complete the input validation:\n\n<input\n  type='email'\n  _____\n  pattern='[a-z0-9._%+-]+@[a-z0-9.-]+\\.[a-z]{2,}$'\n>",options:["validate","mandatory","required","checked"],answer:"required",explanation:"required attribute makes field mandatory. Browser shows error if empty on submit. pattern adds regex validation."},
    {id:9,question:"Complete the script loading:\n\n<script src='app.js' _____></script>\n<!-- Loads async, executes after DOM ready -->",options:["async","defer","lazy","load"],answer:"defer",explanation:"defer: downloads in parallel, executes after DOM fully parsed. async executes as soon as downloaded (may be before DOM ready)."},
    {id:10,question:"Complete the meta viewport:\n\n<meta name='viewport'\n  content='width=device-width, initial-_____=1'>",options:["zoom","scale","size","width"],answer:"scale",explanation:"initial-scale=1 sets initial zoom level to 1 (no zoom). width=device-width + initial-scale=1 = proper responsive viewport."},
  ]},
];